import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Trophy, Heart, Music, Play } from 'lucide-react';
// Sửa đường dẫn thành ../../ để không còn lỗi Module not found
import { useMusic } from '../../context/MusicContext';

const Ranking = () => {
    const [topSongs, setTopSongs] = useState([]);
    // Lấy logic từ Context
    const { favorites, toggleLike, playMusic } = useMusic();

    useEffect(() => {
        axios.get('http://localhost:5000/api/songs/ranking')
            .then(res => setTopSongs(res.data))
            .catch(err => console.error(err));
    }, []);

    return (
        <div style={{ padding: '40px', maxWidth: '800px', margin: '0 auto', fontFamily: 'Arial, sans-serif', paddingBottom: '120px' }}>
            <div style={{ textAlign: 'center', marginBottom: '40px' }}>
                <Trophy size={60} color="#FFD700" style={{ marginBottom: '10px' }} />
                <h1 style={{ color: '#1db954', margin: 0 }}>BẢNG XẾP HẠNG ÂM NHẠC</h1>
                <p style={{ color: '#888' }}>Top bài hát được yêu thích nhất trên P2TUNES</p>
            </div>

            <div style={{ background: '#fff', borderRadius: '20px', overflow: 'hidden', boxShadow: '0 10px 30px rgba(0,0,0,0.1)' }}>
                {topSongs.map((song, index) => {
                    // Kiểm tra trạng thái Like từ Context
                    const isLiked = favorites.includes(String(song._id));

                    return (
                        <div 
                            key={song._id} 
                            style={itemStyle(index)}
                            onClick={() => playMusic(topSongs, index)} // Nhấn vào cả hàng để phát nhạc
                        >
                            <div style={rankBadgeStyle(index)}>
                                {index + 1}
                            </div>

                            <img 
                                src={`http://localhost:5000${song.imageUrl}`} 
                                alt="cover" 
                                style={{ width: '60px', height: '60px', borderRadius: '10px', objectFit: 'cover', marginRight: '20px' }} 
                            />

                            <div style={{ flex: 1 }}>
                                <div style={{ fontWeight: 'bold', fontSize: '18px', color: '#333' }}>
                                    {song.title || song.name}
                                </div>
                                <div style={{ color: '#777', fontSize: '14px' }}>
                                    {song.artist || song.singer}
                                </div>
                            </div>

                            <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                                {/* Nút Like đồng bộ toàn cục */}
                                <button 
                                    onClick={(e) => {
                                        e.stopPropagation(); // Ngăn việc nhấn tim bị kích hoạt phát nhạc
                                        toggleLike(song._id);
                                    }}
                                    style={{ background: 'none', border: 'none', cursor: 'pointer' }}
                                >
                                    <Heart 
                                        size={24} 
                                        fill={isLiked ? "#ff4d4d" : "none"} 
                                        color={isLiked ? "#ff4d4d" : "#ccc"} 
                                        style={{ transition: '0.2s' }}
                                    />
                                </button>
                                
                                <div style={{ textAlign: 'right', minWidth: '40px' }}>
                                    <span style={{ fontSize: '18px', fontWeight: 'bold', color: '#555' }}>
                                        {song.playCount || 0}
                                    </span>
                                    <div style={{ fontSize: '10px', color: '#aaa', textTransform: 'uppercase' }}>Lượt nghe</div>
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

// Giữ nguyên style đẹp của bạn
const itemStyle = (index) => ({
    display: 'flex',
    alignItems: 'center',
    padding: '20px',
    borderBottom: '1px solid #eee',
    background: index === 0 ? '#fffef0' : 'white',
    transition: '0.2s',
    cursor: 'pointer',
    '&:hover': { background: '#f9f9f9' }
});

const rankBadgeStyle = (index) => ({
    width: '35px',
    height: '35px',
    borderRadius: '50%',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    marginRight: '20px',
    fontWeight: 'bold',
    fontSize: '18px',
    background: index === 0 ? '#FFD700' : index === 1 ? '#C0C0C0' : index === 2 ? '#CD7F32' : '#f0f0f0',
    color: index < 3 ? 'white' : '#888'
});

export default Ranking;
